**`endpoints.ts` — Read-modify-write on every partial update**

`updatePhysics`, `updateConstraints`, and `updateRendering` each do a GET before every PUT. Calling two of them in the same flow costs 4 HTTP round-trips instead of 2.

```ts
// CURRENT — 2 requests per update
export const updatePhysics = async (settings: Partial<PhysicsSettings>) => {
  const current = await axios.get(`/api/settings/physics`);         // GET
  const merged = { ...current.data?.data ?? current.data, ...settings };
  return axios.put(`/api/settings/physics`, merged);                // PUT
};
```

```ts
// FIX — Use the existing getAll cache; skip the GET
const _physicsCache: { data: PhysicsSettings | null } = { data: null };

export const updatePhysics = async (settings: Partial<PhysicsSettings>) => {
  const base = _physicsCache.data ?? (await getPhysics()).data;
  _physicsCache.data = { ...base, ...settings } as PhysicsSettings;
  return axios.put(`/api/settings/physics`, _physicsCache.data);
};
```

**`pod-provisioning.ts` — Serial container creation in loop**

```ts
// CURRENT — 4 sequential HTTP calls
for (const memoryType of memoryTypes) {
  await createContainer(jssBaseUrl, `${podPath}agent-memory/${memoryType}/`);
}
```

```ts
// FIX — parallel
await Promise.all(
  memoryTypes.map(t => createContainer(jssBaseUrl, `${podPath}agent-memory/${t}/`))
);
```

---

**`analyticsApi.ts` — Class instantiated per component**

If `AnalyticsAPI` is `new`-ed inside a component body or an effect without a stable ref, a fresh WebSocket is opened on every render cycle.

```tsx
// CURRENT (likely usage pattern) — new instance on every render
function GraphPanel() {
  const api = new AnalyticsAPI();   // ← reopens WS each render
  useEffect(() => { api.subscribeToTask(...) }, []);
}
```

```tsx
// FIX — stable singleton via module scope or useMemo
const analyticsApi = new AnalyticsAPI();   // module level

function GraphPanel() {
  useEffect(() => {
    const unsub = analyticsApi.subscribeToTask(taskId, handler);
    return () => unsub();   // cleanup on unmount
  }, [taskId]);
}
```

**`endpoints.ts` — Path string split on every settings write**

`updateSettingsByPaths` calls `.split('.')` on every path on each invocation, allocating temporary arrays:

```ts
// CURRENT
const key = path.split('.')[2];   // new array every call
```

```ts
// FIX — pre-split or use indexOf for single character
const dotIdx = path.indexOf('.');
const key = dotIdx === -1 ? path : path.slice(dotIdx + 1);
```

---

**`endpoints.ts` — Individual endpoint responses not cached**

Only `getAll()` has a 2-second TTL. `getPhysics()`, `getConstraints()`, `getRendering()` each always hit the network, even though settings change infrequently.

```ts
// ADD — per-endpoint caches matching the existing getAll pattern
const CACHE_TTL_MS = 2000;

type CacheEntry<T> = { data: T; ts: number };
const _physicsCache: CacheEntry<PhysicsSettings> | null = null;
// ... repeat for constraints, rendering

export const getPhysics = async (): Promise<AxiosResponse<PhysicsSettings>> => {
  const now = Date.now();
  if (_physicsCache && now - _physicsCache.ts < CACHE_TTL_MS) {
    return { data: _physicsCache.data } as AxiosResponse<PhysicsSettings>;
  }
  const res = await axios.get<PhysicsSettings>('/api/settings/physics');
  _physicsCache = { data: res.data, ts: now };
  return res;
};
```

**`constraintsApi.ts` — `list()` has no cache**

Constraint lists are stable between user actions; fetching on every mount wastes bandwidth.

```ts
// ADD — stale-while-revalidate with 5s TTL
let _constraintCache: { data: ConstraintListResponse; ts: number } | null = null;
const CONSTRAINT_TTL = 5_000;

export const constraintsApi = {
  list: async (): Promise<AxiosResponse<ConstraintListResponse>> => {
    const now = Date.now();
    if (_constraintCache && now - _constraintCache.ts < CONSTRAINT_TTL) {
      return { data: _constraintCache.data } as AxiosResponse<ConstraintListResponse>;
    }
    const res = await axios.get<ConstraintListResponse>(`${API_BASE}/constraints/list`);
    _constraintCache = { data: res.data, ts: now };
    return res;
  },
  // ...
};
```

